import React, { useState } from "react";
import { UserMinus, Search, UserPlus, X, CheckCircle, AlertCircle } from "lucide-react";
import api from "../../api.js";
import '../../components/Components.css';

const ROLE_COLORS = {
  Lead_Investigator:  { color: "#34d399", bg: "rgba(52,211,153,0.1)" },
  Forensic_Officer:   { color: "#fbbf24", bg: "rgba(251,191,36,0.1)" },
  Police_Officer:     { color: "#60a5fa", bg: "rgba(96,165,250,0.1)" },
  Supervising_Officer:{ color: "#818cf8", bg: "rgba(129,140,248,0.1)" },
};

export default function MembersTab({ members, leadInvestigators, memberDetails, caseId, isAdmin, onRefresh }) {
  const [searchTerm, setSearchTerm]   = useState("");
  const [searchResults, setSearchResults] = useState([]);
  const [showSearch, setShowSearch]   = useState(false);
  const [adding, setAdding]           = useState(false);
  const [removing, setRemoving]       = useState(null);
  const [msg, setMsg]                 = useState({ type: "", text: "" });

  const flash = (type, text) => {
    setMsg({ type, text });
    setTimeout(() => setMsg({ type: "", text: "" }), 3500);
  };

  const handleSearch = async (e) => {
    const val = e.target.value;
    setSearchTerm(val);
    if (val.length >= 1) {
      try {
        const res = await api.get(`/users/search?q=${encodeURIComponent(val)}`);
        // Exclude already-assigned members
        const existingIds = new Set((memberDetails || []).map((m) => String(m.id)));
        setSearchResults((Array.isArray(res.data) ? res.data : []).filter((u) => !existingIds.has(String(u._id))));
      } catch { setSearchResults([]); }
    } else {
      setSearchResults([]);
    }
  };

  const handleAddMember = async (user) => {
    setAdding(true);
    try {
      const res = await api.post(`/case/${caseId}/member`, { user_id: user._id });
      setSearchTerm("");
      setSearchResults([]);
      setShowSearch(false);
      flash("success", res.data?.message || `${user.name} added to case`);
      onRefresh?.();
    } catch (err) {
      flash("error", err.response?.data?.message || "Failed to add member");
    } finally { setAdding(false); }
  };

  const handleRemoveMember = async (userId, name) => {
    if (!window.confirm(`Remove ${name} from this case?`)) return;
    setRemoving(userId);
    try {
      await api.delete(`/case/${caseId}/member/${userId}`);
      flash("success", `${name} removed from case`);
      onRefresh?.();
    } catch (err) {
      flash("error", err.response?.data?.message || "Failed to remove member");
    } finally { setRemoving(null); }
  };

  const details = memberDetails?.length
    ? memberDetails
    : members.map((name) => ({ name, role: null, id: null }));

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "0.75rem" }}>

      {/* Alert banner */}
      {msg.text && (
        <div
          className={`alertBanner ${msg.type === "success" ? "alertSuccess" : "alertError"}`}
          style={{ display: "flex", alignItems: "center", gap: "0.5rem", marginBottom: "0.25rem" }}
        >
          {msg.type === "success" ? <CheckCircle size={15} /> : <AlertCircle size={15} />}
          {msg.text}
        </div>
      )}

      {/* Add Member — admin only */}
      {isAdmin && (
        <div style={{ marginBottom: "0.25rem" }}>
          <button
            onClick={() => { setShowSearch((v) => !v); setSearchTerm(""); setSearchResults([]); }}
            style={{
              display: "flex", alignItems: "center", gap: "0.5rem",
              background: "rgba(79,70,229,0.1)", border: "1px solid rgba(79,70,229,0.25)",
              color: "#818cf8", padding: "0.5rem 1rem", borderRadius: 8,
              cursor: "pointer", fontSize: "0.875rem", fontWeight: 600, transition: "all 0.2s",
            }}
          >
            {showSearch ? <><X size={15} /> Cancel</> : <><UserPlus size={15} /> Add Member</>}
          </button>

          {showSearch && (
            <div style={{ marginTop: "0.75rem", position: "relative" }}>
              <div className="membersSearch" style={{ maxWidth: 380, height: 44 }}>
                <Search size={16} color="#475569" />
                <input
                  type="text"
                  value={searchTerm}
                  onChange={handleSearch}
                  placeholder="Search by name..."
                  autoFocus
                  style={{ background: "transparent", border: "none", outline: "none", flex: 1, fontSize: "0.875rem" }}
                />
                {searchTerm && (
                  <button onClick={() => { setSearchTerm(""); setSearchResults([]); }}
                    style={{ background: "none", border: "none", cursor: "pointer", color: "#64748b", display: "flex" }}>
                    <X size={14} />
                  </button>
                )}
              </div>

              {searchResults.length > 0 && (
                <div className="searchDropdown" style={{ width: 380, zIndex: 50 }}>
                  {searchResults.map((u) => (
                    <div key={u._id} className="searchItem"
                      style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: "0.5rem" }}>
                      <div>
                        <p style={{ margin: 0, fontWeight: 600, fontSize: "0.875rem" }}>{u.name}</p>
                        <p style={{ margin: 0, color: "#64748b", fontSize: "0.75rem" }}>
                          {u.role_id?.role_name?.replace(/_/g, " ")}
                        </p>
                      </div>
                      <button
                        onClick={() => handleAddMember(u)}
                        disabled={adding}
                        style={{
                          background: "rgba(79,70,229,0.2)", border: "1px solid rgba(79,70,229,0.3)",
                          color: "#818cf8", padding: "4px 12px", borderRadius: 6,
                          cursor: adding ? "not-allowed" : "pointer", fontSize: "0.8rem", fontWeight: 600, flexShrink: 0,
                        }}
                      >
                        {adding ? "Adding…" : "Add"}
                      </button>
                    </div>
                  ))}
                </div>
              )}

              {searchTerm.length >= 1 && searchResults.length === 0 && (
                <p style={{ color: "#475569", fontSize: "0.8rem", marginTop: "0.5rem" }}>
                  No users found matching "{searchTerm}"
                </p>
              )}
            </div>
          )}
        </div>
      )}

      {/* Members list */}
      {details.length === 0 ? (
        <div style={{ textAlign: "center", padding: "2rem", color: "#475569" }}>
          <UserPlus size={36} style={{ marginBottom: "0.5rem", opacity: 0.4 }} />
          <p style={{ margin: 0 }}>No members assigned to this case yet.</p>
          {isAdmin && <p style={{ margin: "0.25rem 0 0", fontSize: "0.8rem" }}>Use the button above to add members.</p>}
        </div>
      ) : (
        details.map((member, i) => {
          const isLead = leadInvestigators?.includes(member.name);
          const roleStyle = ROLE_COLORS[member.role] || { color: "#94a3b8", bg: "rgba(148,163,184,0.1)" };
          const isBeingRemoved = removing === String(member.id);

          return (
            <div
              key={member.id || i}
              style={{
                display: "flex", alignItems: "center", justifyContent: "space-between",
                padding: "0.75rem 1rem",
                background: isLead ? "rgba(251,191,36,0.04)" : "rgba(255,255,255,0.03)",
                borderRadius: 8,
                border: isLead ? "1px solid rgba(251,191,36,0.15)" : "1px solid rgba(255,255,255,0.05)",
                transition: "opacity 0.2s",
                opacity: isBeingRemoved ? 0.5 : 1,
              }}
            >
              <div style={{ display: "flex", alignItems: "center", gap: "0.75rem" }}>
                <div className="avatarCircle">
                  {member.name?.charAt(0)?.toUpperCase()}
                </div>
                <div>
                  <p style={{ margin: 0, fontWeight: 600, fontSize: "0.875rem" }}>
                    {member.name}
                    {isLead && (
                      <span style={{ marginLeft: 8, color: "#fbbf24", fontSize: "0.68rem", fontWeight: 700 }}>
                        ★ LEAD
                      </span>
                    )}
                  </p>
                  {member.role && (
                    <span
                      style={{
                        background: roleStyle.bg, color: roleStyle.color,
                        padding: "2px 8px", borderRadius: 4,
                        fontSize: "11px", fontWeight: 700, display: "inline-block", marginTop: 2,
                      }}
                    >
                      {member.role.replace(/_/g, " ")}
                    </span>
                  )}
                </div>
              </div>

              {isAdmin && member.id && (
                <button
                  className="actionCircle"
                  onClick={() => handleRemoveMember(member.id, member.name)}
                  disabled={isBeingRemoved}
                  title={`Remove ${member.name} from case`}
                  style={{ color: "#f87171" }}
                >
                  <UserMinus size={15} />
                </button>
              )}
            </div>
          );
        })
      )}
    </div>
  );
}
